    }

    function setDefaultRoyalty(
        address recipient,
        uint96 feeBps
    ) external onlyOwner {
        require(feeBps <= MAX_ROYALTY_BPS, "Royalty too high");
        _setDefaultRoyalty(recipient, feeBps);
    }

    function resetTokenRoyalty(uint256 tokenId) external onlyOwner {
        _resetTokenRoyalty(tokenId);
    }

